40	export async function createDraftExtension(
41	  userId: string,
42	  raw: ManifestFormValues,
43	): Promise<CreateDraftResult> {
44	  const parsed = ManifestFormSchema.safeParse(raw)
45	  if (!parsed.success) {
46	    return {
47	      ok: false,
48	      error: "invalid_input",
49	      detail: parsed.error.issues.map((i) => i.message).join("; "),
50	    }
51	  }
52	  const data = parsed.data
53	  const cls = defaultClassification(data.category)
54	  const extensionId = crypto.randomUUID()
55	  const versionId = crypto.randomUUID()
56	  const db = useDb()
57	
58	  try {
59	    await db.transaction(async (tx) => {
60	      await tx.insert(extensions).values({
61	        id: extensionId,
62	        slug: data.slug,
63	        name: data.name,
64	        nameZh: emptyToNull(data.nameZh),
65	        tagline: data.summary,
66	        taglineZh: emptyToNull(data.taglineZh),
67	        category: data.category,
68	        scope: data.scope,
69	        funcCat: cls.funcCat,
