273	export async function attachFile(
274	  userId: string,
275	  versionId: string,
276	  r2Key: string,
277	  size: number,
278	  checksumSha256: string,
279	): Promise<AttachFileResult> {
280	  const fileId = crypto.randomUUID()
281	  const db = useDb()
282	
283	  const [owner] = await db
284	    .select({ publisherUserId: extensions.publisherUserId })
285	    .from(extensionVersions)
286	    .innerJoin(extensions, eq(extensions.id, extensionVersions.extensionId))
287	    .where(eq(extensionVersions.id, versionId))
288	    .limit(1)
289	  if (!owner || owner.publisherUserId !== userId) {
290	    return { ok: false, error: "not_found" }
291	  }
292	
293	  try {
294	    await db.transaction(async (tx) => {
295	      await tx.insert(files).values({
296	        id: fileId,
297	        r2Key,
298	        size: BigInt(size),
299	        checksumSha256,
300	        mimeType: "application/zip",
301	        scanStatus: "pending",
302	      })
303	      const updated = await tx
304	        .update(extensionVersions)
305	        .set({ bundleFileId: fileId })
306	        .where(eq(extensionVersions.id, versionId))
307	        .returning({ id: extensionVersions.id })
308	      if (updated.length === 0) throw new Error("version_disappeared")
309	    })
310	  } catch (err) {
311	    console.error("[publish] attachFile failed", err)
312	    return { ok: false, error: "db_error" }
313	  }
314	  return { ok: true, fileId }
