376	export async function getMyExtensions(userId: string) {
377	  const db = useDb()
378	  // Aliased join against `users` so we can pull the display name for whoever
379	  // revoked the extension (if anyone) without colliding with the publisher's
380	  // own user row downstream.
381	  const revoker = alias(users, "revoker")
382	  const rows = await db
383	    .select({
384	      id: extensions.id,
385	      slug: extensions.slug,
386	      name: extensions.name,
387	      category: extensions.category,
388	      visibility: extensions.visibility,
389	      subCat: extensions.subCat,
390	      officialTier: extensions.officialTier,
391	      revokedAt: extensions.revokedAt,
392	      revokedByUserId: extensions.revokedByUserId,
393	      revocationNote: extensions.revocationNote,
394	      revokedByName: revoker.name,
395	      revokedByEmail: revoker.email,
396	      createdAt: extensions.createdAt,
397	      latestVersionId: extensionVersions.id,
398	      latestVersion: extensionVersions.version,
399	      latestStatus: extensionVersions.status,
400	      latestBundleFileId: extensionVersions.bundleFileId,
401	    })
402	    .from(extensions)
403	    .leftJoin(
404	      extensionVersions,
405	      eq(extensionVersions.extensionId, extensions.id),
406	    )
407	    .leftJoin(revoker, eq(revoker.id, extensions.revokedByUserId))
408	    .where(eq(extensions.publisherUserId, userId))
409	    .orderBy(desc(extensions.createdAt), desc(extensionVersions.createdAt))
410	
411	  const byExtension = new Map<string, (typeof rows)[number]>()
412	  for (const row of rows) {
413	    if (!byExtension.has(row.id)) byExtension.set(row.id, row)
414	  }
415	  return Array.from(byExtension.values())
416	}
