import { sql } from "drizzle-orm";
import {
  bigint,
  boolean,
  check,
  customType,
  index,
  integer,
  jsonb,
  numeric,
  pgEnum,
  pgTable,
  primaryKey,
  text,
  timestamp,
  unique,
} from "drizzle-orm/pg-core";

import { users } from "./auth";
import { departments, organizations } from "./org";

// tsvector is a Postgres-native type; Drizzle doesn't ship a built-in helper.
// We declare it as a custom type so the ORM can reference it in WHERE clauses
// via sql``. It is GENERATED ALWAYS (read-only); never written by app code.
const tsvector = customType<{ data: string }>({
  dataType() { return "tsvector"; },
});

export const extensionCategoryEnum = pgEnum("extension_category", [
  "skills",
  "mcp",
  "slash",
  "plugins",
]);

export const extensionScopeEnum = pgEnum("extension_scope", [
  "personal",
  "org",
  "enterprise",
]);

export const extensionBadgeEnum = pgEnum("extension_badge", [
  "official",
  "popular",
  "new",
]);

// Official-tier approval outcome. Null = unofficial (the default for any
// publisher-uploaded extension). Owned by the approval workflow — app code
// outside server/utils/approvals.ts MUST NOT write this column directly.
export const officialTierEnum = pgEnum("extension_official_tier", [
  "productLine",
  "company",
]);

export const funcCatEnum = pgEnum("func_cat", [
  "workTask",
  "business",
  "tools",
]);

export const visibilityEnum = pgEnum("extension_visibility", [
  "draft",
  "published",
  "archived",
]);

export const versionStatusEnum = pgEnum("version_status", [
  "pending",
  "scanning",
  "ready",
  "rejected",
]);

export const fileScanStatusEnum = pgEnum("file_scan_status", [
  "pending",
  "clean",
  "flagged",
]);

// Product-line lookup table — bilingual labels, kebab-case ids
// (`wireless`, `datacom`, `terminals`, `cloud`). Seeded by migration 0009.
// Used as the third axis of the reviewer matrix for the productLine tier,
// and as the company-level "endorsing line" on extensions whose
// officialTier='productLine'. Editable as data, not code, so adding a line
// is a content migration rather than a release.
export const productLines = pgTable("product_lines", {
  id: text().primaryKey(),
  labelEn: text().notNull(),
  labelZh: text().notNull(),
  sortOrder: integer().notNull().default(0),
  createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
});

export const extensions = pgTable(
  "extensions",
  {
    id: text().primaryKey(),
    slug: text().notNull().unique(),
    category: extensionCategoryEnum().notNull(),
    badge: extensionBadgeEnum(),
    scope: extensionScopeEnum().notNull(),
    // Official-tier approval outcome. Null = unofficial. See approval.ts.
    officialTier: officialTierEnum(),
    // Endorsing product line — required iff officialTier='productLine',
    // null otherwise. CHECK constraint below enforces the shape; the
    // approval orchestrator is the only writer. ON DELETE RESTRICT matches
    // the iff-rule: SET NULL would still fail the CHECK for every
    // productLine-tier row, so RESTRICT just surfaces the real outcome.
    productLineId: text().references(() => productLines.id, {
      onDelete: "restrict",
    }),
    // funcCat/subCat are nullable — the redesigned publish wizard does not
    // collect them; admin curation can backfill or system defaults apply.
    funcCat: funcCatEnum(),
    subCat: text(),
    l2: text(),
    publisherUserId: text().references(() => users.id, {
      onDelete: "set null",
    }),
    // Tier revocation audit trail. Populated when a super-admin demotes
    // an Official extension back to Unofficial via the detail page
    // Revoke action. Cleared on the next approval — see the orchestrator
    // in server/utils/approvals.ts. ON DELETE SET NULL on the admin FK
    // so deleting an admin orphans the attribution rather than failing
    // the cascade.
    revokedAt: timestamp({ withTimezone: true }),
    revokedByUserId: text().references(() => users.id, {
      onDelete: "set null",
    }),
    revocationNote: text(),
    ownerOrgId: text()
      .notNull()
      .references(() => organizations.id, { onDelete: "cascade" }),
    deptId: text().references(() => departments.id, { onDelete: "set null" }),
    iconEmoji: text(),
    iconColor: text(),
    visibility: visibilityEnum().notNull().default("draft"),
    // Editorial flag — hand-curated. Surfaces a single extension on the home
    // hero. Coexists with `badge`: badge is a static editorial mark on the
    // card; `featured` is a transient "pick of the week" pointer.
    featured: boolean().notNull().default(false),
    // i18n columns
    name: text().notNull(),
    nameZh: text(),
    tagline: text(),
    taglineZh: text(),
    description: text(),
    descriptionZh: text(),
    // Long-form markdown body for the detail page. Not duplicated to ZH yet —
    // most extensions will have an English README, with translations layered
    // on later if needed.
    readmeMd: text(),
    // metadata for detail page sidebar
    homepageUrl: text(),
    repoUrl: text(),
    licenseSpdx: text(),
    compatibilityJson: jsonb(),
    // Permissions captured during publish (network/files/runtime/data, etc.).
    // Surfaced on the detail page so users see what the extension wants.
    permissions: jsonb().notNull().default({}),
    // denormalized counters (updated by jobs)
    downloadsCount: integer().notNull().default(0),
    starsAvg: numeric({ precision: 2, scale: 1 }).notNull().default("0.0"),
    ratingsCount: integer().notNull().default(0),
    publishedAt: timestamp({ withTimezone: true }),
    createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
    updatedAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
    searchVector: tsvector("search_vector"),
  },
  (t) => [
    index("idx_ext_category").on(t.category),
    index("idx_ext_scope").on(t.scope),
    index("idx_ext_official_tier").on(t.officialTier),
    index("idx_ext_product_line").on(t.productLineId),
    index("idx_ext_func_sub_l2").on(t.funcCat, t.subCat, t.l2),
    index("idx_ext_dept_path").using(
      "btree",
      sql`${t.deptId} text_pattern_ops`,
    ),
    index("idx_ext_visibility").on(t.visibility),
    index("idx_ext_downloads").on(sql`${t.downloadsCount} DESC`),
    index("idx_ext_stars").on(sql`${t.starsAvg} DESC`),
    index("idx_ext_featured_published").on(
      t.featured,
      sql`${t.publishedAt} DESC`,
    ),
    // Shape invariant: productLineId is present iff officialTier='productLine'.
    // Mirrors the same rule on approval_requests and approval_reviewers.
    check(
      "extensions_pl_shape_chk",
      sql`official_tier IS NULL
        OR (official_tier = 'productLine' AND product_line_id IS NOT NULL)
        OR (official_tier = 'company' AND product_line_id IS NULL)`,
    ),
  ],
);

export const extensionVersions = pgTable(
  "extension_versions",
  {
    id: text().primaryKey(),
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    version: text().notNull(), // semver
    changelog: text(),
    changelogZh: text(),
    manifestJson: jsonb(),
    // Logical reference to files.id; no FK constraint to avoid a circular FK
    // with files.extensionVersionId. App code keeps these consistent.
    bundleFileId: text(),
    status: versionStatusEnum().notNull().default("pending"),
    // Source method chosen during publish: zip (only one wired today), git, cli.
    // Stored as text rather than enum so adding methods doesn't require a migration.
    sourceMethod: text().notNull().default("zip"),
    sourceMeta: jsonb().notNull().default({}),
    publishedAt: timestamp({ withTimezone: true }),
    createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
  },
  (t) => [unique("ext_version_unique").on(t.extensionId, t.version)],
);

export const files = pgTable("files", {
  id: text().primaryKey(),
  extensionVersionId: text().references(() => extensionVersions.id, {
    onDelete: "set null",
  }),
  r2Key: text().notNull(),
  size: bigint({ mode: "bigint" }).notNull(),
  checksumSha256: text().notNull(),
  mimeType: text(),
  scanStatus: fileScanStatusEnum().notNull().default("pending"),
  scanReport: jsonb(),
  createdAt: timestamp({ withTimezone: true }).notNull().defaultNow(),
});

export const tags = pgTable("tags", {
  id: text().primaryKey(), // tag key, e.g. "real-time"
  labelEn: text().notNull(),
  labelZh: text().notNull(),
});

export const extensionTags = pgTable(
  "extension_tags",
  {
    extensionId: text()
      .notNull()
      .references(() => extensions.id, { onDelete: "cascade" }),
    tagId: text()
      .notNull()
      .references(() => tags.id, { onDelete: "cascade" }),
  },
  (t) => [
    primaryKey({ columns: [t.extensionId, t.tagId] }),
    index("idx_extension_tags_tag_ext").on(t.tagId, t.extensionId),
  ],
);

import { z } from "zod";

// Slug shape, exported so client-side form validators don't redefine it.
export const SLUG_PATTERN = /^[a-z0-9]+(?:-[a-z0-9]+)*$/;
export const SEMVER_PATTERN = /^\d+\.\d+\.\d+$/;

// "summary" is the redesigned wizard's one-line description; it lands in
// the existing `tagline` column. Capped at 80 chars to match the design.
export const SUMMARY_MAX = 80;

// Single source of truth for what makes an extension manifest valid.
// Mirrors `docs/manifest-spec.md`. Bundle and form schemas below derive
// from this core; nothing should redefine these constraints elsewhere.
export const ExtensionManifestCore = z.object({
  slug: z
    .string()
    .min(3)
    .max(64)
    .regex(SLUG_PATTERN, "Lowercase letters, numbers and hyphens only"),
  name: z.string().min(2).max(80),
  nameZh: z.string().max(80).optional(),
  version: z.string().regex(SEMVER_PATTERN, "Must be semver (e.g. 1.0.0)"),
  category: z.enum(["skills", "mcp", "slash", "plugins"]),
  scope: z.enum(["personal", "org", "enterprise"]),
  funcCat: z.enum(["workTask", "business", "tools"]),
  subCat: z.string().min(1).max(60),
  l2: z.string().max(60).optional(),
  description: z.string().min(1).max(280),
  descriptionZh: z.string().max(280).optional(),
  tagline: z.string().max(120).optional(),
});

// Permissions toggled in the wizard — surfaced on the detail page so users
// know what the extension intends to do before installing.
export const PermissionsSchema = z
  .object({
    network: z.boolean().optional(),
    files: z.boolean().optional(),
    runtime: z.boolean().optional(),
    data: z.boolean().optional(),
  })
  .default({});

// Form: the slimmer field set the redesigned publish wizard collects.
// Notable departures from the prior form:
//   - `summary` (the design's one-line description, max 80) replaces the
//     long `description`/`descriptionZh` pair. Stored in the `tagline` column.
//   - `funcCat` / `subCat` / `l2` are gone from the wizard. Server-side
//     defaults (`defaultClassification`) backfill funcCat/subCat from the
//     chosen `category` so filters keep working.
//   - URL/license fields (homepageUrl, repoUrl, licenseSpdx) are dropped
//     from the wizard; the columns stay nullable in the DB.
//   - `iconColor`, `readmeMd`, `permissions`, `sourceMethod`, `taglineZh`
//     are new in the form and persist directly.
export const ManifestFormSchema = z.object({
  slug: ExtensionManifestCore.shape.slug,
  name: ExtensionManifestCore.shape.name,
  nameZh: ExtensionManifestCore.shape.nameZh,
  version: ExtensionManifestCore.shape.version,
  category: ExtensionManifestCore.shape.category,
  scope: ExtensionManifestCore.shape.scope,
  summary: z.string().min(1, "Required").max(SUMMARY_MAX),
  taglineZh: z.string().max(SUMMARY_MAX).optional(),
  // Bound the README so saveDraft + step transitions don't ship
  // arbitrarily large markdown payloads on every keystroke. 16k is
  // generous for an extension README without ballooning auto-save.
  readmeMd: z.string().max(16_000).optional(),
  iconColor: z
    .enum(["indigo", "amber", "emerald", "rose", "slate"])
    .default("indigo"),
  tagIds: z.array(z.string()).max(8),
  deptId: z.string().optional(),
  permissions: PermissionsSchema,
  sourceMethod: z.literal("zip").default("zip"),
});

export type ManifestFormValues = z.infer<typeof ManifestFormSchema>;

// Bundle: same fields as before, lifted into the [extension] /
// [categorization] TOML sections defined in docs/manifest-spec.md. The
// bundle manifest still carries description + funcCat + subCat — those
// come from whatever produced the bundle (CLI, hand-authored TOML), not
// from the publish wizard, so they remain required at the bundle layer.
export const BundleManifestSchema = z.object({
  extension: ExtensionManifestCore.pick({
    slug: true,
    name: true,
    nameZh: true,
    version: true,
    category: true,
    scope: true,
    description: true,
    descriptionZh: true,
    tagline: true,
  }),
  categorization: ExtensionManifestCore.pick({
    funcCat: true,
    subCat: true,
    l2: true,
  }),
});

export type BundleManifest = z.infer<typeof BundleManifestSchema>;

import { z } from "zod";

const CATEGORIES = ["skills", "mcp", "slash", "plugins"] as const;
const SCOPES = ["personal", "org", "enterprise"] as const;
const FUNC_CATS = ["workTask", "business", "tools"] as const;
const FILTER_CHIPS = ["all", "trending", "new", "official", "free"] as const;
const TIERS = ["unofficial", "productLine", "company"] as const;
const SORTS = ["downloads", "stars", "recent"] as const;
const TAG_MATCHES = ["any", "all"] as const;

export const PAGE_SIZE = 24;

export const filtersSchema = z.object({
  q: z.string().trim().min(1).max(120).optional(),
  category: z.enum(CATEGORIES).optional(),
  scope: z.enum(SCOPES).optional(),
  funcCat: z.enum(FUNC_CATS).optional(),
  subCat: z.string().trim().min(1).max(40).optional(),
  l2: z.string().trim().min(1).max(40).optional(),
  // Department id (dotted-path) or the literal "__all" to disable the filter.
  dept: z.string().trim().min(1).max(120).optional(),
  // Creator = users.id (the user who published). Schema column is named
  // publisherUserId for legacy reasons; we expose it as "creator" everywhere.
  creator: z.string().trim().min(1).max(80).optional(),
  // Publisher = organizations.id (the owning org).
  publisher: z.string().trim().min(1).max(80).optional(),
  tags: z.array(z.string().trim().min(1).max(40)).max(16).optional(),
  tagMatch: z.enum(TAG_MATCHES).optional(),
  filter: z.enum(FILTER_CHIPS).optional(),
  // Three-state official-tier filter: 'unofficial' | 'productLine' | 'company'.
  // Separate from the legacy `filter=official` chip (which now means "any
  // official tier"); `tier=` picks a specific cell.
  tier: z.enum(TIERS).optional(),
  // Optional product-line id (kebab-case). Only meaningful when paired with
  // `tier=productLine`; the listing query still honours it standalone (acts
  // as "narrow to this line") which keeps the filter rail simple.
  productLineId: z
    .string()
    .trim()
    .min(1)
    .max(40)
    .regex(/^[a-z][a-z0-9-]*$/)
    .optional(),
  sort: z.enum(SORTS).optional(),
  page: z.coerce.number().int().min(1).max(1000).optional(),
});

export type Filters = z.infer<typeof filtersSchema>;

/**
 * Parse Next.js searchParams into typed Filters. Invalid input is dropped,
 * so a malformed URL silently falls back to "no filter" rather than 500ing.
 */
export function parseFilters(
  input: Record<string, string | string[] | undefined>,
): Filters {
  const tags = input.tags;
  const normalized = {
    ...input,
    tags:
      tags === undefined
        ? undefined
        : Array.isArray(tags)
          ? tags
          : tags.split(",").filter(Boolean),
  };
  const parsed = filtersSchema.safeParse(normalized);
  return parsed.success ? parsed.data : {};
}

export function pageOffset(page: number | undefined) {
  return ((page ?? 1) - 1) * PAGE_SIZE;
}

/**
 * Adapter from `URLSearchParams` (the runtime shape) to the `Record` shape
 * `parseFilters` consumes. Repeated keys (`?tags=a&tags=b`) accumulate into
 * an array; `serializeFilters` always emits comma-joined, but external
 * links may use the array form and the validator already handles both.
 */
export function searchParamsToInput(
  searchParams: URLSearchParams,
): Record<string, string | string[]> {
  const out: Record<string, string | string[]> = {};
  for (const [key, value] of searchParams.entries()) {
    const prev = out[key];
    if (prev === undefined) {
      out[key] = value;
    } else if (Array.isArray(prev)) {
      prev.push(value);
    } else {
      out[key] = [prev, value];
    }
  }
  return out;
}

/**
 * Inverse of `parseFilters`. Encodes typed filters back into URL search
 * params using the same conventions parseFilters consumes — comma-joined
 * arrays for `tags`, omitted keys for undefined / empty values.
 */
export function serializeFilters(filters: Partial<Filters>): URLSearchParams {
  const params = new URLSearchParams();
  for (const [key, value] of Object.entries(filters)) {
    if (value === undefined || value === "" || value === null) continue;
    if (Array.isArray(value)) {
      if (value.length > 0) params.set(key, value.join(","));
    } else {
      params.set(key, String(value));
    }
  }
  return params;
}

import { z } from "zod"

import {
  ALL_L1_KEYS,
  ALL_L2_KEYS,
  type CategoryLevel,
} from "~~/shared/taxonomy"

const L1_KEY_SET = new Set<string>(ALL_L1_KEYS)
const L2_KEY_SET = new Set<string>(ALL_L2_KEYS)

// `SUB_CAT_KEY_LIST` is the source of truth for the publisher subCat picker
// and the request-row validator — same set as `ALL_L1_KEYS`, just re-exported
// under the historical name so the matrix UI and the publish dialog stay
// in lockstep.
export const SUB_CAT_KEY_LIST: readonly string[] = ALL_L1_KEYS

export const OfficialTier = z.enum(["productLine", "company"])
export type OfficialTier = z.infer<typeof OfficialTier>

export const SubCatKey = z.string().refine((v) => L1_KEY_SET.has(v), {
  message: "must be a key from FUNC_TAXONOMY",
})

export const ExtensionCategory = z.enum(["skills", "mcp", "slash", "plugins"])
export type ExtensionCategory = z.infer<typeof ExtensionCategory>

export const AdminCategoryLevel = z.enum(["all", "macro", "micro"])
export type AdminCategoryLevel = CategoryLevel

// Product-line ids are seeded text PKs in kebab-case (wireless, datacom,
// terminals, cloud as of 0009). Validate the shape here; the DB FK + CHECK
// constraint enforces membership and the iff-rule against the actual tier.
export const ProductLineId = z
  .string()
  .trim()
  .min(1)
  .max(40)
  .regex(/^[a-z][a-z0-9-]*$/, {
    message: "must be a kebab-case product-line id",
  })
export type ProductLineId = z.infer<typeof ProductLineId>

// iff-rule helpers — the DB CHECK is the source of truth, but surfacing
// the rule at the validator layer turns a bad request into a typed Zod
// error instead of a generic 23514 from Postgres.
const requireProductLineIff = <T extends {
  tier?: OfficialTier
  requestedTier?: OfficialTier
  productLineId?: string | undefined
}>(
  v: T,
  tierKey: "tier" | "requestedTier",
): boolean => {
  const tier = v[tierKey]
  const hasPl = !!v.productLineId
  if (tier === "productLine") return hasPl
  if (tier === "company") return !hasPl
  return true
}

export const APPROVAL_REASON_MAX = 500
export const APPROVAL_NOTE_MAX = 500
export const REVOKE_NOTE_MAX = 500

const optionalText = (max: number) =>
  z
    .string()
    .trim()
    .max(max)
    .optional()
    .transform((v) => (v && v.length > 0 ? v : undefined))

export const SubmitApprovalSchema = z
  .object({
    extensionId: z.string().trim().min(1),
    requestedTier: OfficialTier,
    subCat: SubCatKey,
    productLineId: ProductLineId.optional(),
    reason: optionalText(APPROVAL_REASON_MAX),
  })
  .refine((v) => requireProductLineIff(v, "requestedTier"), {
    path: ["productLineId"],
    message: "productLineId is required iff requestedTier=productLine",
  })
export type SubmitApprovalInput = z.infer<typeof SubmitApprovalSchema>

// Discriminated union: a reviewer note only makes sense on a rejection.
// The orchestrator drops any note sent with an approve action anyway —
// making that explicit at the API boundary catches the mistake before
// it crosses the wire instead of silently after.
export const DecideApprovalSchema = z.discriminatedUnion("decision", [
  z.object({
    requestId: z.string().trim().min(1),
    decision: z.literal("approve"),
  }),
  z.object({
    requestId: z.string().trim().min(1),
    decision: z.literal("reject"),
    note: optionalText(APPROVAL_NOTE_MAX),
  }),
])
export type DecideApprovalInput = z.infer<typeof DecideApprovalSchema>

export const WithdrawApprovalSchema = z.object({
  requestId: z.string().trim().min(1),
})
export type WithdrawApprovalInput = z.infer<typeof WithdrawApprovalSchema>

// Super-admin Revoke action from the detail page. The note is REQUIRED
// (mirrors the existing reject flow) — the publisher dashboard surfaces
// it directly so a missing note would leave the publisher in the dark.
// `.trim().min(1)` enforces "non-empty after trim" so whitespace-only
// submissions are caught at the validator boundary.
export const RevokeTierSchema = z.object({
  extensionId: z.string().trim().min(1),
  note: z.string().trim().min(1).max(REVOKE_NOTE_MAX),
})
export type RevokeTierInput = z.infer<typeof RevokeTierSchema>

// Matrix admin assignment — five coordinates. Replaces the 3-coord
// pre-redesign shape. Refines on top of the level/key keyspace and the
// productLineId iff-rule:
//   - level='all' → key='*'
//   - level='macro' → key is an l1 leaf
//   - level='micro' → key is an l2 leaf
//   - productLineId is required iff tier='productLine'
// Both refines surface as Zod errors so the endpoint can render a useful
// message instead of bouncing the raw 23514 from Postgres.
export const AssignAdminSchema = z
  .object({
    extensionCategory: ExtensionCategory,
    tier: OfficialTier,
    productLineId: ProductLineId.optional(),
    categoryLevel: AdminCategoryLevel,
    categoryKey: z.string().trim().min(1).max(40),
    userId: z.string().trim().min(1),
  })
  .refine((v) => requireProductLineIff(v, "tier"), {
    path: ["productLineId"],
    message: "productLineId is required iff tier=productLine",
  })
  .refine(
    (v) => {
      if (v.categoryLevel === "all") return v.categoryKey === "*"
      if (v.categoryLevel === "macro") return L1_KEY_SET.has(v.categoryKey)
      return L2_KEY_SET.has(v.categoryKey)
    },
    {
      path: ["categoryKey"],
      message:
        "categoryKey must be '*' for level=all, an l1 key for level=macro, or an l2 key for level=micro",
    },
  )
export type AssignAdminInput = z.infer<typeof AssignAdminSchema>

export const UnassignAdminSchema = z.object({
  id: z.string().trim().min(1),
})
export type UnassignAdminInput = z.infer<typeof UnassignAdminSchema>

export const ListApprovalsQuerySchema = z.object({
  // "mine"  → requests this user submitted as a publisher
  // "queue" → pending requests routed to this user as a reviewer
