  { extensionCategory: "skills", tier: "productLine", productLineId: "wireless", categoryLevel: "micro", categoryKey: "backend",  reviewerEmail: "ben@agentcenter.dev" },

  // --- MCP tab: a couple of macros + one PL All ---
