  { extensionCategory: "slash", tier: "productLine", productLineId: "wireless", categoryLevel: "macro", categoryKey: "docs", reviewerEmail: "eli@agentcenter.dev" },

  // --- Plugins tab: cover the seeded pending mqtt-bridge request ---
